import cv2
import numpy as np
import torch

from collections import namedtuple
import torch
import torch.nn as nn

from tinygrad import Tensor as tinyTensor, nn as tiny_nn
from torch import Tensor


def to_tiny(x): return tinyTensor(x.detach().numpy())

def to_torch(x): return Tensor(x.numpy())

def to_tiny_seq(x):
    ret = tiny_Seq(size=len(x))
    for i in range(len(x)): ret[i] = x[i]
    return ret

class tiny_Seq():
    def __init__(self, size=0):
        super().__init__()
        self.list = [None] * size
    def __len__(self): return len(self.list)
    def __setitem__(self, key, value): self.list[key] = value
    def __getitem__(self, idx): return self.list[idx]
    def __delitem__(self, idx): del self.list[idx]
    def __call__(self, x):
        for y in self.list: x = y(x)
        return x

class Flatten(nn.Module):
    def forward(self, input):
        input = to_tiny(input)
        output = input.view(input.size(0), -1)
        return to_torch(output)

class BasicBlockIR(nn.Module):
    def __init__(self, in_channel, depth, stride):
        super(BasicBlockIR, self).__init__()
        if in_channel == depth:
            self.shortcut_layer = nn.MaxPool2d(1, stride)
        else:
            self.shortcut_layer = nn.Sequential(
                nn.Conv2d(in_channel, depth, (1, 1), stride, bias=False),
                nn.BatchNorm2d(depth))
        self.res_layer = nn.Sequential(
            nn.BatchNorm2d(in_channel),
            nn.Conv2d(in_channel, depth, (3, 3), (1, 1), 1, bias=False),
            nn.BatchNorm2d(depth),
            nn.PReLU(depth),
            nn.Conv2d(depth, depth, (3, 3), stride, 1, bias=False),
            nn.BatchNorm2d(depth))

    def forward(self, x):
        shortcut = self.shortcut_layer(x)
        res = self.res_layer(x)
        return res + shortcut



sizes = [[64, 64, 2], [64, 64, 1], [64, 64, 1], [64, 128, 2], [128, 128, 1], [128, 128, 1], [128, 128, 1], [128, 256, 2], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 256, 1], [256, 512, 2], [512, 512, 1], [512, 512, 1]]

class Backbone(nn.Module):
    def __init__(self, input_size, num_layers):
        super(Backbone, self).__init__()
        self.input_layer = nn.Sequential(nn.Conv2d(3, 64, (3, 3), 1, 1, bias=False),
                                      nn.BatchNorm2d(64), nn.PReLU(64))
        output_channel = 512

        self.output_layer = nn.Sequential(nn.BatchNorm2d(output_channel),
                                    nn.Dropout(0.4), Flatten(),
                                    nn.Linear(output_channel * 7 * 7, 512),
                                    nn.BatchNorm1d(512, affine=False))

        modules = []
        for size in sizes: modules.append(BasicBlockIR(size[0], size[1], size[2]))
        self.body = nn.Sequential(*modules)


    def forward(self, x):
        x = self.input_layer[0](x)
        x = self.input_layer[1](x)
        x = to_tiny(x)
        x = tinyTensor.where(x > 0, x, self.prelu_weight.view(1, -1, 1, 1) * x)
        x = to_torch(x)
        for module in self.body: x = module(x)

        x = to_tiny(x)
        x = self.bn_tiny(x)
        x = x.view(x.size(0), -1)
        x = self.linear_tiny(x)
        x = self.bn_tiny2(x)
        norm = tinyTensor.sqrt(tinyTensor.sum(x * x, keepdim=True))
        output = x / norm
        output = to_torch(output)
        norm = to_torch(norm)
        return output, norm


def to_input(pil_rgb_image):
    np_img = np.array(pil_rgb_image)
    brg_img = ((np_img[:,:,::-1] / 255.) - 0.5) / 0.5
    tensor = torch.tensor([brg_img.transpose(2,0,1)]).float()
    return tensor

model = Backbone(112, 50)

model.output_layer_tiny = to_tiny_seq(model.output_layer)

statedict = torch.load("adaface_ir50_ms1mv2.ckpt",  map_location="cpu", weights_only=False)['state_dict']
model_statedict = {key[6:]:val for key, val in statedict.items() if key.startswith('model.')}
model.load_state_dict(model_statedict)

del model.output_layer_tiny[1]
model.linear_tiny = tiny_nn.Linear(512 * 7 * 7, 512)
model.linear_tiny.weight = to_tiny(model.output_layer[3].weight)
model.linear_tiny.bias = to_tiny(model.output_layer[3].bias)
model.bn_tiny = tiny_nn.BatchNorm2d(512)
model.bn_tiny.weight = to_tiny(model.output_layer[0].weight)
model.bn_tiny.bias = to_tiny(model.output_layer[0].bias)
model.bn_tiny.running_mean = to_tiny(model.output_layer[0].running_mean)
model.bn_tiny.running_var = to_tiny(model.output_layer[0].running_var)


model.bn_tiny2 = tiny_nn.BatchNorm(512, affine=False)
model.bn_tiny2.running_mean = to_tiny(model.output_layer[4].running_mean)
model.bn_tiny2.running_var = to_tiny(model.output_layer[4].running_var)
#model.bn_tiny2.weight = to_tiny(model.output_layer[4].weight)
#model.bn_tiny2.bias = to_tiny(model.output_layer[4].bias)

model.prelu_weight = to_tiny(model.input_layer[2].weight)

model.eval() # cos dropout


img = cv2.imread('messi_aligned.jpg')
bgr_input = to_input(img)
feature, _ = model(bgr_input)
feature = feature.detach().numpy()[0]
